def sum_product(numbers):
    if not numbers:
        return (0, 1)

    total_sum = 0
    total_product = 1

    for number in numbers:
        total_sum += number
        total_product *= number

    return (total_sum, total_product)

# Example usage:
# print(sum_product([1, 2, 3, 4]))  # Output: (10, 24)
# print(sum_product([-1, -2, -3, -4]))  # Output: (-10, 24)
# print(sum_product([]))  # Output: (0, 1)
# print(sum_product([5]))  # Output: (5, 5)

