def gcd(a, b):
    """
    Return the greatest common divisor (GCD) of two integers.

    :param a: An integer representing the first number.
    :param b: An integer representing the second number.
    :return: An integer representing the greatest common divisor of `a` and `b`.
    """
    # Handle edge cases where either a or b is zero
    if a == 0:
        return abs(b)
    if b == 0:
        return abs(a)

    # Use the Euclidean algorithm to find the GCD
    while b != 0:
        a, b = b, a % b

    return a

