def largest_divisor(n):
    """
    Find the largest divisor of a given number n that is smaller than n.

    :param n: An integer representing the number for which to find the largest divisor.
    :return: An integer representing the largest divisor of n that is smaller than n.
    """
    if n <= 1:
        return 0
    for i in range(n - 1, 0, -1):
        if n % i == 0:
            return i
    return 1  # This line is technically unreachable due to the loop condition

