import math

def is_prime(n):
    """
    Determine if a given integer is a prime number.

    :param n: An integer representing the number to check for primality.
    :return: A boolean value indicating whether `n` is a prime number.
    """
    if n < 2:
        return False
    if n == 2:
        return True
    if n % 2 == 0:
        return False
    max_divisor = int(math.sqrt(n))
    for divisor in range(3, max_divisor + 1, 2):
        if n % divisor == 0:
            return False
    return True

