def encode_shift(s):
    """
    Encodes a string by shifting each character by 5 positions in the alphabet.

    :param s: A string representing the input text to be encoded.
    :return: A string representing the encoded text.
    """
    if not s:
        return ""

    encoded = []
    for char in s:
        if char.isalpha():
            shift = 5
            if char.islower():
                base = ord('a')
            else:
                base = ord('A')
            encoded_char = chr((ord(char) - base + shift) % 26 + base)
            encoded.append(encoded_char)
        else:
            encoded.append(char)

    return ''.join(encoded)

def decode_shift(s):
    """
    Decodes a string by shifting each character by 5 positions in the alphabet.

    :param s: A string representing the input text to be decoded.
    :return: A string representing the decoded text.
    """
    if not s:
        return ""

    decoded = []
    for char in s:
        if char.isalpha():
            shift = -5
            if char.islower():
                base = ord('a')
            else:
                base = ord('A')
            decoded_char = chr((ord(char) - base + shift) % 26 + base)
            decoded.append(decoded_char)
        else:
            decoded.append(char)

    return ''.join(decoded)

