def is_monotonic(l):
    """
    Determine if a list of numbers is monotonically increasing or decreasing.

    :param l: List of numbers
    :return: Boolean indicating if the list is monotonically increasing or decreasing
    """
    if not l:
        return True  # An empty list is considered monotonically increasing and decreasing

    increasing = decreasing = True

    for i in range(1, len(l)):
        if l[i] > l[i - 1]:
            decreasing = False
        elif l[i] < l[i - 1]:
            increasing = False

    return increasing or decreasing

