def is_product_of_three_distinct_primes(a):
    """
    Determine if a given number is the product of three distinct prime numbers.

    :param a: An integer representing the number to check.
    :return: A boolean value indicating whether `a` is the product of three distinct prime numbers.
    """
    if a < 2:
        return False

    def is_prime(n):
        """Check if a number is prime."""
        if n <= 1:
            return False
        if n <= 3:
            return True
        if n % 2 == 0 or n % 3 == 0:
            return False
        i = 5
        while i * i <= n:
            if n % i == 0 or n % (i + 2) == 0:
                return False
            i += 6
        return True

    primes = [i for i in range(2, int(sqrt(a)) + 1) if is_prime(i)]

