def encrypt(s):
    if not s:
        return ""

    encrypted = []
    for char in s:
        if char.isalpha():
            shift = 2
            if char.islower():
                base = ord('a')
            else:
                base = ord('A')

            # Calculate the new character position, wrapping around the alphabet
            new_char = chr((ord(char) - base + shift) % 26 + base)
            encrypted.append(new_char)
        else:
            # Non-alphabetic characters remain unchanged
            encrypted.append(char)

    return ''.join(encrypted)

# Example usage:
print(encrypt(''))  # Output: ''
print(encrypt('a'))  # Output: 'c'
print(encrypt('z'))  # Output: 'b'
print(encrypt('Z'))  # Output: 'C'

