def closest_integer(value: str) -> int:
    """
    Rounds a string representation of a number to the nearest integer,
    rounding away from zero if the number is equidistant between two integers.

    :param value: A string representing a number.
    :return: An integer representing the closest integer to the input number,
             rounded away from zero if necessary.
    """
    # Convert the string to a float
    num = float(value)

    # Check if the number is exactly halfway between two integers
    if abs(num - round(num)) == 0.5:
        return int(num + (1 if num > 0 else -1))
    else:
        return round(num)

