    # Check if there are enough even numbers in lst2 to replace all odd numbers in lst1
    even_count_in_lst2 = sum(1 for num in lst2 if num % 2 == 0)
    odd_count_in_lst1 = sum(1 for num in lst1 if num % 2 != 0)

    # If there are enough even numbers in lst2, return "YES"
