def histogram(test):
    if not test:
        return {}

    # Split the input string into individual letters
    letters = test.split()

    # Create a dictionary to store the frequency of each letter
    frequency = {}

    # Count the frequency of each letter
    for letter in letters:
        if letter in frequency:
            frequency[letter] += 1
        else:
            frequency[letter] = 1

    # Find the maximum frequency
    max_frequency = max(frequency.values(), default=0)

    # Create a dictionary to store the letters with the maximum frequency
    result = {letter: count for letter, count in frequency.items() if count == max_frequency}

    return result

