def is_sorted(lst):
    """
    Determine if a list of integers is sorted in ascending order with no more than one duplicate of any number.

    :param lst: List of integers.
    :return: Boolean value indicating whether the list is sorted in ascending order without more than one duplicate.
    """
    if not lst:
        return True

    prev = lst[0]
    count = 1

    for num in lst[1:]:
        if num < prev:
            return False
        if num == prev:
            count += 1
            if count > 1:
                return False
        else:
            count = 1
        prev = num

    return True

