def prod_signs(arr):
    if not arr:
        return None

    sign_product = 1
    magnitude_sum = 0

    for num in arr:
        if num == 0:
            return 0
        elif num < 0:
            sign_product *= -1
        magnitude_sum += abs(num)

    return magnitude_sum * sign_product

