def tri(n):
    # Initialize the base cases of the Tribonacci sequence
    if n == 0:
        return [1]
    elif n == 1:
        return [1, 3]

    # Initialize the list with the first three numbers of the Tribonacci sequence
    tribonacci = [1, 3, 2]

    # Generate the rest of the sequence up to the nth number
    for i in range(3, n + 1):
        next_value = tribonacci[i - 1] + tribonacci[i - 2] + tribonacci[i - 3]
        tribonacci.append(next_value)

    return tribonacci

