def can_arrange(arr):
    # Edge case: if the array is empty or has only one element, return -1
    if len(arr) <= 1:
        return -1

    # Iterate through the array from the second last element to the first
    for i in range(len(arr) - 2, -1, -1):
        # Check if the current element is not greater than or equal to the previous element
        if arr[i] > arr[i + 1]:
            return i

    # If no such index is found, return -1
    return -1

